public class ArithmeticDemo {
    public static void main(String[] args) {
        // Basic arithmetic
        int a = 17, b = 5;
        System.out.println(a + b);   // 22
        System.out.println(a - b);   // 12
        System.out.println(a * b);   // 85
        System.out.println(a / b);   // 3  (INTEGER division — truncates!)
        System.out.println(a % b);   // 2  (remainder)

        // Integer division TRUNCATES toward zero (not floor)
        System.out.println( 7 / 2);  //  3 (not 3.5)
        System.out.println(-7 / 2);  // -3 (not -4, truncates toward zero)
        System.out.println( 7 % 2);  //  1
        System.out.println(-7 % 2);  // -1 (sign follows DIVIDEND in Java)

        // Division by zero
        // int x = 5 / 0;  // ArithmeticException: / by zero
        // double d = 5.0 / 0;  // Infinity (no exception!)
        System.out.println(5.0 / 0);   // Infinity
        System.out.println(-5.0 / 0);  // -Infinity
        System.out.println(0.0 / 0);   // NaN

        // Pre/post increment
        int x = 5;
        System.out.println(x++);  // 5 (returns THEN increments)
        System.out.println(x);    // 6
        System.out.println(++x);  // 7 (increments THEN returns)
        System.out.println(x);    // 7

        // Compound assignment operators
        int y = 10;
        y += 5;   // y = 15
        y -= 3;   // y = 12
        y *= 2;   // y = 24
        y /= 4;   // y = 6
        y %= 4;   // y = 2
        System.out.println("y = " + y);  // 2
    }
}

public class BitwiseDemo {
    // Unix-style file permissions using bits
    static final int READ    = 0b100;  // 4
    static final int WRITE   = 0b010;  // 2
    static final int EXECUTE = 0b001;  // 1

    public static void main(String[] args) {
        // Bitwise AND (&): both bits must be 1
        System.out.println(0b1010 & 0b1100);  // 0b1000 = 8

        // Bitwise OR (|): either bit is 1
        System.out.println(0b1010 | 0b1100);  // 0b1110 = 14

        // Bitwise XOR (^): exactly one bit is 1
        System.out.println(0b1010 ^ 0b1100);  // 0b0110 = 6

        // Bitwise NOT (~): flips all bits
        System.out.println(~0b00000001);       // -2 (all bits flipped in 32-bit int)

        // Permission manipulation
        int perms = READ | WRITE;  // 0b110 = 6
        System.out.println("Can read:    " + ((perms & READ)    != 0));  // true
        System.out.println("Can write:   " + ((perms & WRITE)   != 0));  // true
        System.out.println("Can execute: " + ((perms & EXECUTE) != 0)); // false

        // Set a permission: perms |= EXECUTE
        perms |= EXECUTE;  // add execute
        System.out.println("After +exec: " + Integer.toBinaryString(perms)); // 111

        // Clear a permission: perms &= ~EXECUTE
        perms &= ~WRITE;  // remove write
        System.out.println("After -write: " + Integer.toBinaryString(perms)); // 101

        // Toggle a permission: perms ^= EXECUTE
        perms ^= READ;  // toggle read
        System.out.println("After ^read: " + Integer.toBinaryString(perms));  // 001
    }
}

public class ShiftDemo {
    public static void main(String[] args) {
        // Left shift (<<): multiply by 2^n
        int x = 1;
        System.out.println(x << 0);  //  1  (1 * 2^0)
        System.out.println(x << 1);  //  2  (1 * 2^1)
        System.out.println(x << 2);  //  4  (1 * 2^2)
        System.out.println(x << 10); // 1024 (1 * 2^10)

        // Right shift (>>): divide by 2^n (arithmetic — preserves sign)
        int y = 100;
        System.out.println(y >> 1);  // 50  (100 / 2)
        System.out.println(y >> 2);  // 25  (100 / 4)

        // Right shift of negative: arithmetic (sign-extended)
        int neg = -100;
        System.out.println(neg >> 1);  // -50  (sign bit extended)
        System.out.println(neg >> 31); // -1   (all bits become sign bit value)

        // Unsigned right shift (>>>): zero-fills left (logical shift)
        System.out.println(-1 >>> 1);   // 2147483647 (Integer.MAX_VALUE)
        System.out.println(-1 >>> 0);   // -1 (shift by 0: unchanged)

        // PRACTICAL: extract color channels from ARGB int
        int argb = 0xFF_AA_BB_CC;  // alpha=255, red=170, green=187, blue=204
        int alpha = (argb >> 24) & 0xFF;  // 255
        int red   = (argb >> 16) & 0xFF;  // 170
        int green = (argb >>  8) & 0xFF;  // 187
        int blue  =  argb        & 0xFF;  // 204
        System.out.printf("ARGB: alpha=%d red=%d green=%d blue=%d%n",
            alpha, red, green, blue);

        // Power of 2 check: n & (n-1) == 0
        for (int n : new int[]{1, 2, 3, 4, 7, 8, 16, 31, 32}) {
            System.out.printf("%2d is power of 2: %s%n",
                n, (n > 0 && (n & (n-1)) == 0));
        }
    }
}

public class LogicalDemo {
    static int callCount = 0;

    static boolean check(String name, boolean value) {
        callCount++;
        System.out.println("  Checking: " + name + " = " + value);
        return value;
    }

    public static void main(String[] args) {
        // SHORT-CIRCUIT AND (&&): stops if first is false
        callCount = 0;
        boolean r1 = check("A", false) && check("B", true);
        System.out.println("Result: " + r1 + ", calls: " + callCount);
        // Prints: Checking A = false. (B never checked!)
        // Result: false, calls: 1

        // SHORT-CIRCUIT OR (||): stops if first is true
        callCount = 0;
        boolean r2 = check("A", true) || check("B", false);
        System.out.println("Result: " + r2 + ", calls: " + callCount);
        // Result: true, calls: 1 (B never checked)

        // NON-SHORT-CIRCUIT (&): always evaluates BOTH sides
        callCount = 0;
        boolean r3 = check("A", false) & check("B", true);
        System.out.println("Result: " + r3 + ", calls: " + callCount);
        // Result: false, calls: 2 (B IS evaluated)

        // NULL GUARD with short-circuit
        String s = null;
        // Safe: if s==null, second part not evaluated
        boolean hasContent = s != null && !s.isEmpty(); // false, no NPE
        // Unsafe: both sides evaluated
        // boolean bad = s != null & !s.isEmpty(); // NullPointerException!

        // Logical NOT (!)
        System.out.println(!true);   // false
        System.out.println(!false);  // true
        System.out.println(!(3 > 2)); // false
    }
}

public class SpecialOpsDemo {
    public static void main(String[] args) {
        // TERNARY: condition ? valueIfTrue : valueIfFalse
        int x = 10;
        String label = (x > 5) ? "big" : "small";
        System.out.println(label);  // big

        // Nested ternary (readable with parentheses)
        int score = 75;
        String grade = score >= 90 ? "A"
                     : score >= 80 ? "B"
                     : score >= 70 ? "C"
                     : score >= 60 ? "D" : "F";
        System.out.println(grade);  // C

        // INSTANCEOF
        Object obj = "Hello";
        if (obj instanceof String s) {  // Pattern matching instanceof (Java 16+)
            System.out.println(s.toUpperCase());  // HELLO — s is already cast!
        }

        // Old style (Java 15 and earlier)
        if (obj instanceof String) {
            String s2 = (String) obj;  // explicit cast still needed
            System.out.println(s2.length());
        }

        // OPERATOR PRECEDENCE surprises
        System.out.println(2 + 3 * 4);     // 14 (not 20) — * before +
        System.out.println(10 - 3 - 2);    // 5  (not 9)  — left-to-right
        System.out.println(true || false && false); // true — && before ||
        System.out.println((true || false) && false); // false — parens override

        // String + with non-strings
        System.out.println("Value: " + 1 + 2);  // "Value: 12" (not 13!)
        System.out.println("Value: " + (1 + 2)); // "Value: 3"
        System.out.println(1 + 2 + " Value");   // "3 Value" — left-to-right
    }
}

