public class Q1 {
    public static boolean isPowerOfTwo(int n) {
        return n > 0 && (n & (n-1)) == 0;
        // n > 0: exclude 0 and negatives
        // n & (n-1): clears lowest set bit. If only one bit set (power of 2), result is 0
    }

