public class Q2 {
    public static int countBitsSimple(int n) {
        int count = 0;
        for (int i = 0; i < 32; i++) {
            if ((n & 1) == 1) count++;
            n >>>= 1; // unsigned right shift — handles negative numbers
        }
        return count;
    }

    public static int countBitsKernighan(int n) {
        int count = 0;
        // Kernighan: n & (n-1) always clears the lowest set bit
        // Count iterations until n becomes 0
        while (n != 0) {
            n &= (n - 1); // clear lowest set bit
            count++;
        }
        return count;
        // Kernighan is faster when bits are sparse (few 1s)
    }

    public static void main(String[] args) {
        for (int n : new int[]{0, 1, 7, 8, 255, -1}) {
            System.out.printf("%4d: simple=%d kernighan=%d builtin=%d%n",
                n, countBitsSimple(n), countBitsKernighan(n), Integer.bitCount(n));
        }
        // -1 (all 32 bits set) should show count=32
    }
}

