problems.solutionCode:
public class Q3 {
    public static int[] xorSwap(int a, int b) {
        // XOR swap — no temp variable
        // Step 1: a = a ^ b (a now holds combined bits)
        a ^= b;
        // Step 2: b = (a^b) ^ b = a (original a recovered)
        b ^= a;
        // Step 3: a = (a^b) ^ a = b (original b in a)
        a ^= b;
        return new int[]{a, b};
        // Proof: let a0, b0 be original values
        // After step 1: a = a0^b0, b = b0
        // After step 2: b = (a0^b0)^b0 = a0^(b0^b0) = a0^0 = a0
        // After step 3: a = (a0^b0)^a0 = (a0^a0)^b0 = 0^b0 = b0
    }

    public static int[] arithmeticSwap(int a, int b) {
        // Arithmetic swap — overflow risk for large values!
        a = a + b; // a = a+b (may overflow)
        b = a - b; // b = (a+b) - b = a (original a)
        a = a - b; // a = (a+b) - a = b (original b)
        return new int[]{a, b};
    }

    public static void main(String[] args) {
        System.out.println(java.util.Arrays.toString(xorSwap(5, 10)));        // [10, 5]
        System.out.println(java.util.Arrays.toString(arithmeticSwap(5, 10))); // [10, 5]

        // XOR swap same-location pitfall: a == b (same variable)
        int x = 5;
        x ^= x; // x = x^x = 0! Same location problem
        System.out.println("Same-location XOR: " + x); // 0 (WRONG!)
        // Solution: always check (i != j) before XOR-swapping array elements
    }
}

