public class Q5 {
    static int leftCalls = 0, rightCalls = 0;
    static boolean left(boolean val)  { leftCalls++;  return val; }
    static boolean right(boolean val) { rightCalls++; return val; }

    public static int[][] testShortCircuit() {
        int[][] results = new int[4][2];
        // Test 1: false && true — right NOT evaluated
        leftCalls = rightCalls = 0;
        left(false) && right(true);
        results[0] = new int[]{leftCalls, rightCalls}; // [1, 0]

        // Test 2: true || false — right NOT evaluated
        leftCalls = rightCalls = 0;
        left(true) || right(false);
        results[1] = new int[]{leftCalls, rightCalls}; // [1, 0]

        // Test 3: true && false — right IS evaluated
        leftCalls = rightCalls = 0;
        left(true) && right(false);
        results[2] = new int[]{leftCalls, rightCalls}; // [1, 1]

        // Test 4: false || true — right IS evaluated
        leftCalls = rightCalls = 0;
        left(false) || right(true);
        results[3] = new int[]{leftCalls, rightCalls}; // [1, 1]

        return results;
    }

    public static void main(String[] args) {
        int[][] r = testShortCircuit();
        String[] exprs = {"false && true","true || false","true && false","false || true"};
        for (int i = 0; i < 4; i++)
            System.out.printf("%s: left=%d right=%d%n", exprs[i], r[i][0], r[i][1]);
        // false && true: left=1 right=0 (short-circuit)
        // true  || false: left=1 right=0 (short-circuit)
        // true  && false: left=1 right=1 (both evaluated)
        // false || true:  left=1 right=1 (both evaluated)
    }
}

