public class Q6 {
    static final int READ    = 0b100; // 4
    static final int WRITE   = 0b010; // 2
    static final int EXECUTE = 0b001; // 1

    public static int setPermission(int perms, int flag) {
        return perms | flag;  // turn on bits
    }

    public static int clearPermission(int perms, int flag) {
        return perms & ~flag; // turn off bits
    }

    public static boolean hasPermission(int perms, int flag) {
        return (perms & flag) == flag; // all bits of flag must be set
    }

    public static String getPermissionString(int perms) {
        return "" +
            (hasPermission(perms, READ)    ? 'r' : '-') +
            (hasPermission(perms, WRITE)   ? 'w' : '-') +
            (hasPermission(perms, EXECUTE) ? 'x' : '-');
    }

    public static void main(String[] args) {
        int perms = 0;
        perms = setPermission(perms, READ | WRITE);
        System.out.println(getPermissionString(perms)); // rw-
        perms = setPermission(perms, EXECUTE);
        System.out.println(getPermissionString(perms)); // rwx
        perms = clearPermission(perms, WRITE);
        System.out.println(getPermissionString(perms)); // r-x
        System.out.println(hasPermission(perms, READ));  // true
        System.out.println(hasPermission(perms, WRITE)); // false

        // Unix chmod 755
        int owner = READ | WRITE | EXECUTE;
        int group = READ | EXECUTE;
        int others = READ | EXECUTE;
        System.out.printf("chmod 755: %s%s%s%n",
            getPermissionString(owner), getPermissionString(group), getPermissionString(others));
    }
}

