public class Q7 {
    public static int evaluate(String expr) {
        int[] i = {0};
        return parseExpr(expr.replaceAll("\\s", ""), i);
    }

    static int parseExpr(String s, int[] i) {
        int val = parseTerm(s, i);
        while (i[0] < s.length() && (s.charAt(i[0]) == '+' || s.charAt(i[0]) == '-')) {
            char op = s.charAt(i[0]++);
            int right = parseTerm(s, i);
            val = (op == '+') ? val + right : val - right;
        }
        return val;
    }

    static int parseTerm(String s, int[] i) {
        int val = parseFactor(s, i);
        while (i[0] < s.length() && (s.charAt(i[0]) == '*' || s.charAt(i[0]) == '/')) {
            char op = s.charAt(i[0]++);
            int right = parseFactor(s, i);
            val = (op == '*') ? val * right : val / right;
        }
        return val;
    }

    static int parseFactor(String s, int[] i) {
        if (s.charAt(i[0]) == '(') {
            i[0]++; // skip '('
            int val = parseExpr(s, i);
            i[0]++; // skip ')'
            return val;
        }
        // Parse number (possibly multi-digit)
        int start = i[0];
        while (i[0] < s.length() && Character.isDigit(s.charAt(i[0]))) i[0]++;
        return Integer.parseInt(s.substring(start, i[0]));
    }

    public static void main(String[] args) {
        System.out.println(evaluate("2 + 3 * 4"));    // 14
        System.out.println(evaluate("(2 + 3) * 4")); // 20
        System.out.println(evaluate("10 - 3 - 2"));   // 5
        System.out.println(evaluate("100 / 10 / 2")); // 5
        System.out.println(evaluate("2 * (3 + 4) - 1")); // 13
    }
}

