problems.solutionCode:
public class Q8 {
    public static int reverseBits(int n) {
        int result = 0;
        for (int i = 0; i < 32; i++) {
            result = (result << 1) | (n & 1); // take LSB of n, add to result
            n >>>= 1; // unsigned shift: fills with 0 (not sign bit)
        }
        return result;
    }

    public static void main(String[] args) {
        // 1 = 00000000000000000000000000000001
        // reversed: 10000000000000000000000000000000 = -2147483648
        System.out.println("reverseBits(1) = " + reverseBits(1));
        System.out.printf("Binary: %s%n", Integer.toBinaryString(reverseBits(1)));

        // Palindrome bit pattern: 10000000000000000000000000000001 (2^31 + 1)
        int palindrome = 0x80000001;
        System.out.println("reverseBits(0x80000001) = " + reverseBits(palindrome));
        // Same value (bit palindrome)

        // All zeros and all ones
        System.out.println("reverseBits(0) = " + reverseBits(0));  // 0
        System.out.println("reverseBits(-1) = " + reverseBits(-1)); // -1 (all 1s reversed = all 1s)
    }
}

