public class Q9 {
    public static int singleNumber(int[] nums) {
        int result = 0;
        for (int n : nums) result ^= n;
        // All paired numbers XOR to 0
        // 0 ^ uniqueNumber = uniqueNumber
        return result;
    }

    // Extension: find two unique numbers (exactly two appear once)
    public static int[] twoSingleNumbers(int[] nums) {
        int xorBoth = 0;
        for (int n : nums) xorBoth ^= n; // XOR of the two unique numbers

        // Find a bit that differs between the two unique numbers
        int diffBit = xorBoth & (-xorBoth); // isolate lowest set bit

        // Split into two groups by diffBit, XOR each group
        int a = 0, b = 0;
        for (int n : nums) {
            if ((n & diffBit) != 0) a ^= n;
            else b ^= n;
        }
        return new int[]{a, b};
    }

    public static void main(String[] args) {
        System.out.println(singleNumber(new int[]{2, 2, 1}));        // 1
        System.out.println(singleNumber(new int[]{4, 1, 2, 1, 2})); // 4

        System.out.println(java.util.Arrays.toString(
            twoSingleNumbers(new int[]{1, 2, 1, 3, 2, 5}))); // [3, 5]
    }
}

