public class Q10 {
    public static int add(int a, int b) {
        while (b != 0) {
            int carry = (a & b) << 1; // bits that need to carry
            a = a ^ b;                // sum without carry
            b = carry;                // new 'b' is the carry
        }
        return a;
        // Recursive version:
        // return b == 0 ? a : add(a ^ b, (a & b) << 1);
    }

    public static int subtract(int a, int b) {
        // -b in two's complement = ~b + 1
        return add(a, add(~b, 1));
    }

    public static int multiply(int a, int b) {
        // Multiplication via repeated addition (slow but correct)
        boolean negative = (a < 0) ^ (b < 0);
        int absA = a < 0 ? add(~a, 1) : a;
        int absB = b < 0 ? add(~b, 1) : b;
        int result = 0;
        while (absB != 0) {
            if ((absB & 1) == 1) result = add(result, absA);
            absA <<= 1;
            absB >>>= 1;
        }
        return negative ? add(~result, 1) : result;
    }

    public static void main(String[] args) {
        System.out.println(add(5, 3));        // 8
        System.out.println(add(-1, 1));       // 0
        System.out.println(add(0, 0));        // 0
        System.out.println(subtract(10, 3));  // 7
        System.out.println(subtract(5, 8));   // -3
        System.out.println(multiply(3, 4));   // 12
