public class Q12 {
    static final class ModInt {
        final int value;
        final int mod;

        ModInt(int value, int mod) {
            this.mod = mod;
            this.value = ((value % mod) + mod) % mod;
        }

        ModInt add(ModInt other) {
            return new ModInt(this.value + other.value, mod);
        }
        ModInt subtract(ModInt other) {
            return new ModInt(this.value - other.value, mod); // constructor handles negative
        }
        ModInt multiply(ModInt other) {
            return new ModInt((int)((long)this.value * other.value % mod), mod);
        }
        ModInt pow(int exp) {
            if (exp == 0) return new ModInt(1, mod);
            if (exp % 2 == 0) {
                ModInt half = pow(exp / 2);
                return half.multiply(half); // fast exponentiation
            }
            return this.multiply(pow(exp - 1));
        }

        @Override public String toString() { return value + " (mod " + mod + ")"; }
    }

    public static void main(String[] args) {
        int M = 7;
        ModInt a = new ModInt(10, M); // 10 mod 7 = 3
        ModInt b = new ModInt(5, M);  // 5 mod 7 = 5
