public class Q14 {
    public static long multiply(long a, long b) {
        if (a == 0 || b == 0) return 0;
        boolean negative = (a < 0) ^ (b < 0);
        long absA = a < 0 ? -a : a; // Math.abs equivalent (no unary -... actually - is ok for unary)
        long absB = b < 0 ? -b : b;

        long result = 0;
        while (absB > 0) {
            if ((absB & 1) == 1) {       // if lowest bit of absB is set
                result += absA;          // add a * (bit value)
            }
            absA <<= 1;                  // double a (next bit's contribution)
            absB >>>= 1;                 // process next bit of b
        }
        return negative ? -result : result;
    }

    // Version using the shift decomposition explicitly
    public static long multiplyExplicit(long a, long b) {
        if (b < 0) return -multiplyExplicit(a, -b);
        long result = 0;
        for (int bit = 0; bit < 63; bit++) {
            if ((b & (1L << bit)) != 0) {
                result += a << bit; // a * 2^bit
            }
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println(multiply(5, 6));        // 30
        System.out.println(multiply(12, 13));      // 156
        System.out.println(multiply(-3, 4));       // -12
        System.out.println(multiply(0, 100));      // 0
        System.out.println(multiplyExplicit(7, 8)); // 56
    }
}

