public class Q16 {
    public static int hammingDistance(int x, int y) {
        return Integer.bitCount(x ^ y);
        // XOR: bits that differ are 1. bitCount counts those 1s.
    }

    public static int totalHammingDistance(int[] nums) {
        int total = 0;
        for (int bit = 0; bit < 32; bit++) {
            int ones = 0;
            for (int n : nums) ones += (n >> bit) & 1; // count set bits at position 'bit'
            total += ones * (nums.length - ones); // ones * zeros = differing pairs
        }
        return total;
        // O(32*n) vs brute force O(n²)
    }

    public static void main(String[] args) {
        System.out.println(hammingDistance(1, 4));  // 1=001, 4=100, differ at 2 positions → 2
        System.out.println(hammingDistance(3, 1));  // 3=011, 1=001, differ at 1 position  → 1

        int[] nums = {4, 14, 2};
        // 4=00100, 14=01110, 2=00010
        // (4,14)=2, (4,2)=2, (14,2)=2 → total=6
        System.out.println(totalHammingDistance(nums)); // 6
    }
}

