import java.util.*;

public class Q17 {
    public static List<Integer> generateGrayCode(int n) {
        int size = 1 << n; // 2^n
        List<Integer> codes = new ArrayList<>(size);
        for (int i = 0; i < size; i++) {
            codes.add(i ^ (i >> 1)); // Gray code formula
        }
        return codes;
    }

    public static boolean verifyGrayCode(List<Integer> codes) {
        for (int i = 0; i + 1 < codes.size(); i++) {
            int diff = codes.get(i) ^ codes.get(i + 1);
            if (Integer.bitCount(diff) != 1) return false; // must differ by exactly 1 bit
        }
        // Also check wrap-around (optional): last and first should also differ by 1
        // For standard Gray code, this is guaranteed
        return true;
    }

    public static int grayToBinary(int gray) {
        // Convert Gray code back to binary
        int binary = gray;
        for (int mask = gray >> 1; mask != 0; mask >>= 1) {
            binary ^= mask;
        }
        return binary;
    }

    public static void main(String[] args) {
        List<Integer> code = generateGrayCode(3);
        System.out.println("3-bit Gray code:");
        for (int i = 0; i < code.size(); i++) {
            System.out.printf("  %d: binary=%s gray=%s%n",
                i, toBin(i, 3), toBin(code.get(i), 3));
        }
        System.out.println("Valid Gray code: " + verifyGrayCode(code));

        // Decode back
        for (int g : code) {
            System.out.printf("Gray %s → binary %d%n", toBin(g, 3), grayToBinary(g));
        }
    }

    static String toBin(int n, int bits) {
        return String.format("%" + bits + "s", Integer.toBinaryString(n)).replace(' ', '0');
    }
}

