public class Q18 {
    public static int maxAndBrute(int[] nums) {
        int max = 0;
        for (int i = 0; i < nums.length; i++)
            for (int j = i+1; j < nums.length; j++)
                max = Math.max(max, nums[i] & nums[j]);
        return max;
    }

    public static int maxAndOptimized(int[] nums) {
        int ans = 0;
        List<Integer> candidates = new ArrayList<>();
        for (int n : nums) candidates.add(n);

        for (int bit = 29; bit >= 0; bit--) {
            int tentative = ans | (1 << bit);
            // Keep only candidates that have all bits of tentative set
            List<Integer> filtered = new ArrayList<>();
            for (int c : candidates) {
                if ((c & tentative) == tentative) filtered.add(c);
            }
            if (filtered.size() >= 2) {
                ans = tentative;     // can include this bit
                candidates = filtered; // narrow down candidates
            }
        }
        return ans;
    }

