public class Q19 {
    public static int numDecodings(String s) {
        if (s == null || s.isEmpty() || s.charAt(0) == '0') return 0;

        int n = s.length();
        int prev2 = 1; // dp[0]: empty prefix has 1 way
        int prev1 = 1; // dp[1]: first char (non-zero) has 1 way

        for (int i = 2; i <= n; i++) {
            int curr = 0;

            // Single digit: s[i-1] is '1'-'9'
            if (s.charAt(i-1) != '0') curr += prev1;

            // Two digits: s[i-2..i-1] is 10-26
            int twoDigit = Integer.parseInt(s.substring(i-2, i));
            if (twoDigit >= 10 && twoDigit <= 26) curr += prev2;

            prev2 = prev1;
            prev1 = curr;
        }
        return prev1;
    }

    public static void main(String[] args) {
        System.out.println(numDecodings("12"));    // 2
        System.out.println(numDecodings("226"));   // 3
        System.out.println(numDecodings("06"));    // 0
        System.out.println(numDecodings("11106")); // 2
        System.out.println(numDecodings("10"));    // 1 (J only)
        System.out.println(numDecodings("27"));    // 1 (BG only, 27>26)
    }
}

