public class Q20 {
    public static int[] findMissingAndDuplicate(int[] nums) {
        int n = nums.length;

        // XOR of all elements XOR 1..n = missing ^ duplicate
        int xorAll = 0;
        for (int num : nums) xorAll ^= num;
        for (int i = 1; i <= n; i++) xorAll ^= i;
        // xorAll = missing ^ duplicate (all others cancelled)

        // Find a bit that differs between missing and duplicate
        int diffBit = xorAll & (-xorAll); // lowest set bit

        // Split into two groups by diffBit
        int group1 = 0, group2 = 0;
        for (int num : nums) {
            if ((num & diffBit) != 0) group1 ^= num;
            else group2 ^= num;
        }
        for (int i = 1; i <= n; i++) {
            if ((i & diffBit) != 0) group1 ^= i;
            else group2 ^= i;
        }
        // group1 and group2 are the two candidates (missing and duplicate, order unknown)

        // Determine which is missing and which is duplicate
        // Check if group1 appears in array
        boolean group1InArray = false;
        for (int num : nums) if (num == group1) { group1InArray = true; break; }

        return group1InArray
            ? new int[]{group1, group2}  // group1=duplicate, group2=missing
            : new int[]{group2, group1}; // group2=duplicate, group1=missing
    }

    public static void main(String[] args) {
        // [duplicate, missing]
        System.out.println(java.util.Arrays.toString(
            findMissingAndDuplicate(new int[]{1, 2, 2, 4}))); // [2, 3]
        System.out.println(java.util.Arrays.toString(
            findMissingAndDuplicate(new int[]{1, 1})));        // [1, 2]
        System.out.println(java.util.Arrays.toString(
            findMissingAndDuplicate(new int[]{3, 1, 2, 5, 3}))); // [3, 4]
    }
